import React from 'react';
import EyePanel from './components/EyePanel';
import './App.css';

const BRAND = 'RU SHAKTI'.split('');

export default function App() {
  return (
    <div className="app">
      <div className="bg-glow" />

      {/* LEFT — eye */}
      <section className="panel panel-eye">
        <EyePanel />
      </section>

      {/* RIGHT — brand text */}
      <section className="panel panel-text">
        <h1 className="brand-title" aria-label="Ru Shakti">
          {BRAND.map((ch, i) => (
            <span
              key={i}
              className={`brand-letter${ch === ' ' ? ' brand-space' : ''}`}
              style={{ animationDelay: `${2.2 + i * 0.11}s` }}
            >
              {ch === ' ' ? '\u00A0' : ch}
            </span>
          ))}
        </h1>
        <p className="tagline">Empowering Strength &bull; Inspiring Grace</p>
      </section>
    </div>
  );
}
